+import { type AnyColumn } from '~/column.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+
+export type FrameBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { type: 'preceding' | 'following'; value: number };
+
+export interface WindowFrameSpec {
+	from: FrameBoundary;
+	to: FrameBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function validateFrameOffset(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+}
+
+export function preceding(value: number): FrameBoundary {
+	validateFrameOffset('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): FrameBoundary {
+	validateFrameOffset('following', value);
+	return { type: 'following', value };
+}
+
+function boundaryPosition(boundary: FrameBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function boundarySql(boundary: FrameBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === currentRow) return sql.raw('current row');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	return sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.type)}`;
+}
+
+export class WindowFrame {
+	constructor(readonly type: 'rows' | 'range', readonly spec: WindowFrameSpec) {}
+
+	getSQL(): SQL {
+		return sql`${sql.raw(this.type)} between ${boundarySql(this.spec.from)} and ${boundarySql(this.spec.to)}`;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: WindowFrameSpec): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be after the "to" boundary');
+	}
+	return new WindowFrame(type, spec);
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: WindowFrameSpec): WindowFrame {
+	return frame('range', spec);
+}
+
+function windowSpecSql(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	}
+	if (spec.frame) parts.push(spec.frame.getSQL());
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${windowSpecSql(spec)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return windowFunction('ntile', [positionalArgument(buckets)]);
+}
+
+export function lag<T extends SQLWrapper>(expression: T, offset?: number): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: SQLWrapper): WindowFunction<NonNullable<ExpressionData<T>>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionData<T> | null> {
+	return windowFunction('lag', [expression, ...(offset === undefined ? [] : [positionalArgument(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export function lead<T extends SQLWrapper>(expression: T, offset?: number): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: SQLWrapper): WindowFunction<NonNullable<ExpressionData<T>>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionData<T> | null> {
+	return windowFunction('lead', [expression, ...(offset === undefined ? [] : [positionalArgument(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<ExpressionData<T> | null> {
+	positiveInteger('nthValue', nth);
+	return windowFunction('nth_value', [expression, positionalArgument(nth)]);
+}
+export function windowSum<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('sum', [expression]); }
+export function windowAvg<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [expression ?? sql.raw('*')]); }
